import{_ as a,o as e,c as n,ae as i}from"./chunks/framework.BGHOrOyn.js";const t="/gitbook-personnal-docs/assets/image%20(12).f86lSg7W.",l="/gitbook-personnal-docs/assets/image%20(13).Sz2KfRl_.",p="/gitbook-personnal-docs/assets/image%20(14).CyrU_-Iq.",E=JSON.parse('{"title":"Page 1","description":"","frontmatter":{},"headers":[],"relativePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/page-1/README.md","filePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/page-1/README.md"}'),o={name:"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/page-1/README.md"};function h(r,s,d,c,k,g){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="page-1" tabindex="-1">Page 1 <a class="header-anchor" href="#page-1" aria-label="Permalink to &quot;Page 1&quot;">​</a></h1><h2 id="why-would-i-do-this" tabindex="-1">Why would I do this? <a class="header-anchor" href="#why-would-i-do-this" aria-label="Permalink to &quot;Why would I do this?&quot;">​</a></h2><p>Learning Kubernetes has been on my list for awhile but the prices for managed clusters at the cloud providers are just too high for something I want to play around with infrequently. I love the idea of self-hosting my own resources, so I started looking into how to have my own cluster locally.</p><p>There are lots of guides on how to setup k3s (a slimmer Kubernetes distro) on raspberry pi&#39;s, but I unfortunately don&#39;t have enough laying around for this project. Also the pi has an ARM processor. That adds a new complexity to this process I do not want to get involved with yet.</p><p>What I do have is a machine in my closet running Proxmox VE, and there is absolutely no reason I cannot create a cluster using virtual machines within it. But I struggled to find a single guide that led me through this process in the way I wanted to do it.</p><p>So here is that guide.</p><h3 id="preface" tabindex="-1">Preface <a class="header-anchor" href="#preface" aria-label="Permalink to &quot;Preface&quot;">​</a></h3><p>This setup uses Proxmox VMs as opposed to LXC containers. You could probably make this work with LXC containers, but I have found that when using container tech, a VM works much more smoothly.</p><p>My server running Proxmox has the following specs:</p><ul><li>64GB of RAM</li><li>8th gen core i7 4-core/8-thread processor</li><li>1 TB NVMe storage</li></ul><p>I used Debian as my OS for my k3s nodes, but any linux OS should work. Many of the details I list in this guide assume Debian is the OS. You may need to change a few things.</p><p>You also need to install <code>kubectl</code> on your local machine. I do not describe how to do this here.</p><p>To install MetalLB I used <code>helm</code>. To do this you will need helm installed on your local machine.</p><h3 id="create-a-template-vm" tabindex="-1">Create a template VM <a class="header-anchor" href="#create-a-template-vm" aria-label="Permalink to &quot;Create a template VM&quot;">​</a></h3><p>Create a new virtual machine and install your favorite version of Linux. For mine I used <code>Debian 10</code>.</p><p>Run <code>apt-get update</code> and <code>apt-get upgrade</code> to make sure it is fully up-to-date.</p><p>Create a user account for yourself and give it sudo permissions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## This assumes you are using a debian flavor of linux</span></span>
<span class="line"><span>adduser YOURNAME</span></span>
<span class="line"><span>usermod -aG sudo YOURNAME</span></span></code></pre></div><p>Install any packages you want to be available on all nodes. You can install these later as well, but doing it now will make it easier on yourself. I recommend installing <code>curl</code> now.</p><p>Shutdown the VM.</p><p>Right click on the VM and click <code>convert to template</code> and name it something like k3s-template.</p><p><img src="`+t+'" alt=""></p><h3 id="create-the-master-node-from-the-template" tabindex="-1">Create the master node from the template <a class="header-anchor" href="#create-the-master-node-from-the-template" aria-label="Permalink to &quot;Create the master node from the template&quot;">​</a></h3><p>Right click the template and click clone. Set the name as something like <code>k3s-master</code> and set the <code>Mode</code> to <code>full clone</code>.</p><p><img src="'+l+`" alt=""></p><p>Once the clone is complete, start that new VM.</p><h3 id="set-a-static-ip" tabindex="-1">Set a static IP <a class="header-anchor" href="#set-a-static-ip" aria-label="Permalink to &quot;Set a static IP&quot;">​</a></h3><p>For this and all machines, a static IP needs to be set. Ideally this should be done with an address outside of your DHCP pool of addresses.</p><p>Edit your <code>/etc/network/interfaces</code> file. It should look initially something like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## This file describes the network interfaces available on your system</span></span>
<span class="line"><span>## and how to activate them. For more information, see interfaces(5).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>source /etc/network/interfaces.d/*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## The loopback network interface</span></span>
<span class="line"><span>auto lo</span></span>
<span class="line"><span>iface lo inet loopback</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## The primary network interface</span></span>
<span class="line"><span>allow-hotplug ens18</span></span>
<span class="line"><span>iface ens18 inet dhcp  # CHANGE THIS TO STATIC</span></span></code></pre></div><p>You want to change it from <code>dhcp</code> to <code>static</code> on the last line and specify an appropriate <code>address</code>, <code>netmask</code>, <code>gateway</code>, and <code>dns-nameservers</code> for your network. My final version looked something like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## This file describes the network interfaces available on your system</span></span>
<span class="line"><span>## and how to activate them. For more information, see interfaces(5).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>source /etc/network/interfaces.d/*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## The loopback network interface</span></span>
<span class="line"><span>auto lo</span></span>
<span class="line"><span>iface lo inet loopback</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## The primary network interface</span></span>
<span class="line"><span>allow-hotplug ens18</span></span>
<span class="line"><span>iface ens18 inet static</span></span>
<span class="line"><span>        address 10.1.0.202</span></span>
<span class="line"><span>        netmask 255.255.0.0</span></span>
<span class="line"><span>        gateway 10.1.0.1</span></span>
<span class="line"><span>        dns-nameservers 10.1.0.3</span></span></code></pre></div><h3 id="change-the-hostname-of-the-system" tabindex="-1">Change the hostname of the system <a class="header-anchor" href="#change-the-hostname-of-the-system" aria-label="Permalink to &quot;Change the hostname of the system&quot;">​</a></h3><p>Next change the hostname of the system to something unique. I used the naming scheme <code>k3s-master</code> and <code>k3s-agent-1</code>, <code>k3s-agent-2</code>... and so on.</p><p>You need to change the hostname in 2 different places.</p><p>Run this command to change the hostname:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Run this on your master node</span></span>
<span class="line"><span>sudo hostnamectl set-hostname k3s-master</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## If setting up a worker node you could do this</span></span>
<span class="line"><span>sudo hostnamectl set-hostname k3s-agent-1</span></span></code></pre></div><p>Next edit the hostname in the <code>/etc/hosts</code> file.</p><p>Change the line starting with <code>127.0.1.1</code> to your new hostname. Everything else you can leave alone.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">127.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">       localhost</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">127.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">       k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s-master</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">## The following lines are desirable for IPv</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> capable hosts</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     localhost ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-localhost ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-loopback</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ff</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-allnodes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ff</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-allrouters</span></span></code></pre></div><h3 id="reboot" tabindex="-1">Reboot <a class="header-anchor" href="#reboot" aria-label="Permalink to &quot;Reboot&quot;">​</a></h3><p>Now reboot the machine. Once it&#39;s back on, make sure it has the correct hostname and has the correct static IP address you set.</p><h3 id="repeat-for-additional-nodes" tabindex="-1">Repeat for additional nodes <a class="header-anchor" href="#repeat-for-additional-nodes" aria-label="Permalink to &quot;Repeat for additional nodes&quot;">​</a></h3><p>Repeat the above for all nodes you want to add to the cluster. Just make sure they all have unique IP addresses and unique hostnames.</p><p>You can name them anything you want, but make sure you at least know which one is your master node in the cluster.</p><p>On my cluster I created one master and two worker nodes.</p><p><img src="`+p+`" alt=""></p><h3 id="install-k3s-on-the-master-node" tabindex="-1">Install k3s on the master node <a class="header-anchor" href="#install-k3s-on-the-master-node" aria-label="Permalink to &quot;Install k3s on the master node&quot;">​</a></h3><p>This process should only be completed on the node designated to be the master node.</p><p>Connect to the master node via SSH or using the proxmox console and run the install script.</p><blockquote><p><strong>Warning</strong></p><p>Important note: By default, k3s comes with a service called <code>klipper-lb</code> to handle load balancing. This will interfere with MetalLB and needs to be disabled for it to work correctly. The install command below disables klipper-lb.</p></blockquote><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sfL https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get.k3s.io </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sh </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> server </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">disable servicelb</span></span></code></pre></div><p>After the install completes you need three pieces of information:</p><ul><li>The static IP address of this master node</li><li>The master node token generated during the install</li><li>The kubeconfig file located at <code>/etc/rancher/k3s/k3s.yaml</code>. Download this to your local machine.</li></ul><p>You can get the master node token by reading it from a file on the master node:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## This must be read with root permissions</span></span>
<span class="line"><span>sudo cat /var/lib/rancher/k3s/server/node-token</span></span>
<span class="line"><span>\`\`\`javascript</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Install k3s on the worker nodes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>On each worker node you need to run the install script with the two pieces of information above:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`javascript</span></span>
<span class="line"><span>curl -sfL https://get.k3s.io | K3S_URL=https://$YOURIPADDRESS:6443 K3S_TOKEN=$YOURNODETOKEN sh -</span></span>
<span class="line"><span>\`\`\`javascript</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Connect to your new cluster</span></span>
<span class="line"><span></span></span>
<span class="line"><span>On your local machine set the \`KUBECONFIG\` environmental variable to the path of your \`k3s.yaml\`. On Linux you could do this:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`javascript</span></span>
<span class="line"><span>export KUBECONFIG=/path/to/k3s.yaml</span></span></code></pre></div><p>Now you should be able to connect to and see your cluster nodes:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">kubectl get nodes</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">## OUTPUT SHOULD LOOK SOMETHING LIKE</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NAME          STATUS   ROLES                  AGE   VERSION</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s-agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   Ready    &lt;none&gt;                 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d    v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">+k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s-agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   Ready    &lt;none&gt;                 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d   v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">+k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s-master    Ready    control-plane,master   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d   v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">+k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><p>You now have a working Kubernetes cluster created with Proxmox VMs.</p><h3 id="installing-metallb" tabindex="-1">Installing MetalLB <a class="header-anchor" href="#installing-metallb" aria-label="Permalink to &quot;Installing MetalLB&quot;">​</a></h3><p>Getting MetalLB up and running is extremely simple using helm. Note: You need helm installed on your local machine to do this.</p><p>MetalLB hands out IP addresses to your Kubernetes services. For it to do this safely, you need to designate a range of IP addresses that will not otherwise be utilized on your network. These should not be in the DHCP address pool and not assigned to anything else.</p><p>Create the following file <code>values.yaml</code>:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">configInline:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  address</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pools:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> name: default</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     protocol: layer2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     addresses:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">     -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.255.2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10.2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.255.254</span></span></code></pre></div><p>On the final line, specify the range of IP addresses you want MetalLB to hand out. In this example I set <code>10.1.255.2</code> through <code>10.2.255.254</code>.</p><p>Now you can install MetalLB from the helm repo, and pass in this new file you created:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Add the helm repo</span></span>
<span class="line"><span>helm repo add metallb https://metallb.github.io/metallb</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Install metallb</span></span>
<span class="line"><span>helm install metallb metallb/metallb -f values.yaml</span></span></code></pre></div><p>Once all of the pods come online you should be able to create services of <code>type: LoadBalancer</code> and MetalLB will assign them an IP address from your pool.</p><h3 id="congratulations" tabindex="-1">Congratulations <a class="header-anchor" href="#congratulations" aria-label="Permalink to &quot;Congratulations&quot;">​</a></h3><p>Everything is complete. You can now experiment and learn Kubernetes locally without having to pay any cloud provider!</p>`,70)])])}const y=a(o,[["render",h]]);export{E as __pageData,y as default};
